// C0684 · REST CRUD JSON (GET/POST/PUT/DELETE)
import jakarta.ws.rs.*;
import jakarta.ws.rs.core.MediaType;
import java.util.*;

@Path("/items")
@Produces(MediaType.APPLICATION_JSON)
@Consumes(MediaType.APPLICATION_JSON)
public class ItemsResource {
  static final Map<Integer, Map<String,Object>> items = new LinkedHashMap<>();
  static int seq = 1;

  @GET public Collection<Map<String,Object>> list(){ return items.values(); }

  @POST public Map<String,Object> create(Map<String,Object> body){
    var it = new LinkedHashMap<String,Object>();
    it.put("id", seq++);
    it.put("name", String.valueOf(body.getOrDefault("name","")));
    items.put((Integer)it.get("id"), it);
    return it;
  }
}

