// C0685 · Middleware logging + tiempo de respuesta
import jakarta.ws.rs.container.*;
import jakarta.ws.rs.ext.Provider;

@Provider
public class TimingFilter implements ContainerRequestFilter, ContainerResponseFilter {
  @Override
  public void filter(ContainerRequestContext req){ req.setProperty("t0", System.currentTimeMillis()); }

  @Override
  public void filter(ContainerRequestContext req, ContainerResponseContext res){
    long t0 = (long) req.getProperty("t0");
    System.out.println(req.getMethod() + " " + req.getUriInfo().getPath() + " " + (System.currentTimeMillis()-t0) + "ms");
  }
}

